import{_ as e,o as n,c as t,a2 as i}from"./chunks/framework.DtwafDNl.js";const h=JSON.parse('{"title":"Outbound Campaigns","description":"","frontmatter":{},"headers":[],"relativePath":"features/campaigns.md","filePath":"features/campaigns.md"}'),s={name:"features/campaigns.md"};function o(l,a,c,r,d,p){return n(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="outbound-campaigns" tabindex="-1">Outbound Campaigns <a class="header-anchor" href="#outbound-campaigns" aria-label="Permalink to &quot;Outbound Campaigns&quot;">​</a></h1><p>Outbound Campaigns let you call a list of contacts without manually dialing each number. You upload a CSV contact list, choose the campaign settings, and schedule when the campaign should run.</p><p>The dialer uses a sliding concurrency window so the campaign keeps multiple calls in progress without overwhelming operators or trunks. Busy and no-answer outcomes can be retried according to the campaign rules, while each contact keeps a clear attempt history.</p><p>Campaigns move through a simple lifecycle from draft to scheduled, running, stopping, and completed states. Live counters show progress while the campaign is active, making it easy to see how many contacts were dialed, answered, failed, or are still pending.</p><h2 id="how-the-dialler-works" tabindex="-1">How the dialler works <a class="header-anchor" href="#how-the-dialler-works" aria-label="Permalink to &quot;How the dialler works&quot;">​</a></h2><h3 id="campaign-configuration" tabindex="-1">Campaign configuration <a class="header-anchor" href="#campaign-configuration" aria-label="Permalink to &quot;Campaign configuration&quot;">​</a></h3><p>Each campaign has three required settings:</p><ul><li><strong>Contact list</strong> — a CSV of phone numbers to dial</li><li><strong>Trunk</strong> — the SIP trunk to use for all outbound calls</li><li><strong>Max concurrency</strong> — the maximum number of simultaneous active calls</li></ul><h3 id="scheduling-and-execution" tabindex="-1">Scheduling and execution <a class="header-anchor" href="#scheduling-and-execution" aria-label="Permalink to &quot;Scheduling and execution&quot;">​</a></h3><p>A NestJS cron job checks for campaigns whose scheduled start time has been reached. When a campaign is due, the cron job hands execution to the Stasis campaign executor.</p><h3 id="sliding-window-loop" tabindex="-1">Sliding window loop <a class="header-anchor" href="#sliding-window-loop" aria-label="Permalink to &quot;Sliding window loop&quot;">​</a></h3><p>The Stasis campaign executor runs a sliding window loop:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│           sliding window dialler        │</span></span>
<span class="line"><span>│                                         │</span></span>
<span class="line"><span>│  maxConcurrent = 3                      │</span></span>
<span class="line"><span>│                                         │</span></span>
<span class="line"><span>│  [call 1 ████████░░░░░░░░░░░░░░░░░░]   │</span></span>
<span class="line"><span>│  [call 2 ████░░░░░░░░░░░░░░░░░░░░░░]   │</span></span>
<span class="line"><span>│  [call 3 ██████████░░░░░░░░░░░░░░░░]   │</span></span>
<span class="line"><span>│            ▲                            │</span></span>
<span class="line"><span>│            └─ when any call ends,       │</span></span>
<span class="line"><span>│               next contact dials        │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre></div><ol><li>Check how many calls are currently active (tracked in Redis)</li><li>While <code>active calls &lt; maxConcurrent</code>, dial the next contact from the list</li><li>Apply <code>formatDialNumber</code> with the trunk&#39;s <code>dial_format</code> to clean and format the number before dialing</li><li>When a call ends, decrement the active call count and fill the window again with the next contact</li><li>Continue until all contacts are dialled, or until the campaign is paused or stopped from the UI</li></ol><h3 id="call-outcomes" tabindex="-1">Call outcomes <a class="header-anchor" href="#call-outcomes" aria-label="Permalink to &quot;Call outcomes&quot;">​</a></h3><p>Each outbound call result is written back to the database via Redis events published by Stasis:</p><table tabindex="0"><thead><tr><th>Outcome</th><th>Description</th></tr></thead><tbody><tr><td><code>answered</code></td><td>Caller picked up</td></tr><tr><td><code>no-answer</code></td><td>No response within the configured timeout</td></tr><tr><td><code>busy</code></td><td>Destination returned busy</td></tr><tr><td><code>failed</code></td><td>Call could not be placed (trunk error, invalid number)</td></tr></tbody></table><p>Busy and no-answer contacts can be retried based on the campaign retry settings. Each contact record tracks the full attempt history.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>CSV contact upload</li><li>Campaign scheduling</li><li>Sliding-window concurrent dialing</li><li>Retry logic for busy outcomes</li><li>Retry logic for no-answer outcomes</li><li>Campaign state lifecycle tracking</li><li>Live progress counters</li><li>Per-contact attempt history</li></ul>`,20)])])}const m=e(s,[["render",o]]);export{h as __pageData,m as default};
